import requests, warnings, json
warnings.filterwarnings('ignore')

session = requests.Session()
session.headers.update({'User-Agent': 'Mozilla/5.0'})

# Try World Bank API for Georgia GDP with longer timeout
url = 'https://api.worldbank.org/v2/country/GE/indicator/NY.GDP.MKTP.KD?format=json&per_page=60'
try:
    resp = session.get(url, timeout=30, verify=False)
    data = json.loads(resp.content)
    gdp_data = {}
    for item in data[1]:
        year = int(item['date'])
        val = item['value']
        if val is not None:
            gdp_data[year] = val
    for y in sorted(gdp_data):
        print(f'{y}: {gdp_data[y]:,.2f}')
except Exception as e:
    print(f'Error: {e}')
PYEOF", "description": "Get World Bank GDP data with longer timeout"}

